diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..f4a68c60a82e 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1820,6 +1820,90 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
     return nullptr;

   FCmpInst::Predicate PredL = LHS->getPredicate(), PredR = RHS->getPredicate();
+
+  // Check for (fcmp pred X, C1) and/or (fcmp pred X, C2) where pred is the same
+  // and X is the same (possibly with swapped operands).
+  // For OR: take the comparison with the "larger" range (e.g., olt with larger const)
+  // For AND: take the comparison with the "smaller" range (e.g., olt with smaller const)
+  if (PredL == PredR) {
+    Value *LHSCompareOp = LHS0, *LHSConstOp = LHS1;
+    Value *RHSCompareOp = RHS0, *RHSConstOp = RHS1;
+
+    // Check if operands are swapped (C1 cmp X vs X cmp C1)
+    const APFloat *LHSConst = nullptr, *RHSConst = nullptr;
+    bool LHSReversed = false, RHSReversed = false;
+
+    if (match(LHS1, m_APFloat(LHSConst)) && match(RHS1, m_APFloat(RHSConst))) {
+      // Both constants on RHS, operands on LHS
+    } else if (match(LHS0, m_APFloat(LHSConst)) && match(RHS0, m_APFloat(RHSConst))) {
+      // Both constants on LHS, operands on RHS (reversed)
+      LHSReversed = true;
+      RHSReversed = true;
+    } else if (match(LHS1, m_APFloat(LHSConst)) && match(RHS0, m_APFloat(RHSConst))) {
+      // LHS constant on RHS, RHS constant on LHS (RHS reversed)
+      RHSReversed = true;
+    } else if (match(LHS0, m_APFloat(LHSConst)) && match(RHS1, m_APFloat(RHSConst))) {
+      // LHS constant on LHS, RHS constant on RHS (LHS reversed)
+      LHSReversed = true;
+    } else {
+      // Not comparing against constants
+      LHSConst = nullptr;
+    }
+
+    if (LHSConst && RHSConst && LHSCompareOp == RHSCompareOp) {
+      // Same operand, same predicate, both constants - can simplify
+      // Determine which comparison is more restrictive based on predicate
+      bool ShouldPickLHS = false;
+      bool CanSimplify = true;
+
+      switch (PredL) {
+      case FCmpInst::FCMP_OLT:
+      case FCmpInst::FCMP_ORD:
+      case FCmpInst::FCMP_ULT:
+        // x < C1 OR x < C2 -> x < max(C1, C2)
+        // x < C1 AND x < C2 -> x < min(C1, C2)
+        if (IsAnd)
+          ShouldPickLHS = LHSConst->compare(*RHSConst) == APFloat::cmpLessThan;
+        else
+          ShouldPickLHS = LHSConst->compare(*RHSConst) == APFloat::cmpGreaterThan;
+        break;
+      case FCmpInst::FCMP_OGT:
+      case FCmpInst::FCMP_UGT:
+        // x > C1 OR x > C2 -> x > min(C1, C2)
+        // x > C1 AND x > C2 -> x > max(C1, C2)
+        if (IsAnd)
+          ShouldPickLHS = LHSConst->compare(*RHSConst) == APFloat::cmpGreaterThan;
+        else
+          ShouldPickLHS = LHSConst->compare(*RHSConst) == APFloat::cmpLessThan;
+        break;
+      case FCmpInst::FCMP_OLE:
+      case FCmpInst::FCMP_ULE:
+        // x <= C1 OR x <= C2 -> x <= max(C1, C2)
+        // x <= C1 AND x <= C2 -> x <= min(C1, C2)
+        if (IsAnd)
+          ShouldPickLHS = LHSConst->compare(*RHSConst) != APFloat::cmpGreaterThan;
+        else
+          ShouldPickLHS = LHSConst->compare(*RHSConst) != APFloat::cmpLessThan;
+        break;
+      case FCmpInst::FCMP_OGE:
+      case FCmpInst::FCMP_UGE:
+        // x >= C1 OR x >= C2 -> x >= min(C1, C2)
+        // x >= C1 AND x >= C2 -> x >= max(C1, C2)
+        if (IsAnd)
+          ShouldPickLHS = LHSConst->compare(*RHSConst) != APFloat::cmpLessThan;
+        else
+          ShouldPickLHS = LHSConst->compare(*RHSConst) != APFloat::cmpGreaterThan;
+        break;
+      default:
+        CanSimplify = false;
+        break;
+      }
+
+      if (CanSimplify)
+        return ShouldPickLHS ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+    }
+  }
+
   auto AbsOrSelfLHS0 = m_CombineOr(m_Specific(LHS0), m_FAbs(m_Specific(LHS0)));
